parameters.jsCode:
const stories = $input.first().json.stories;
const issues = [];

for (const story of stories) {
  const content = story.content;
  if (!content) continue;

  const seoIssues = [];

  // Check for missing meta description
  if (!content.seo_description && !content.seo?.description) {
    seoIssues.push('missing_meta_description');
  }

  // Check for missing page title / headline in hero
  const sections = Array.isArray(content.section) ? content.section : [];
  const hero = sections.find(s => s.component === 'hero');
  if (hero && (!hero.headline || hero.headline.length < 10)) {
    seoIssues.push('weak_hero_headline');
  }

  // Check for very short content
  if (sections.length < 2) {
    seoIssues.push('thin_content');
  }

  if (seoIssues.length > 0) {
    issues.push({
      storyId: story.id,
      slug: story.full_slug,
      name: story.name,
      issues: seoIssues,
      currentContent: content
    });
  }
}

return issues.map(i => ({ json: i }));

parameters.prompt:
=Page: {{ $json.slug }}
Current issues: {{ $json.issues.join(', ') }}

Generate:
1. A compelling meta description (150-160 chars) if missing
2. An improved hero headline if weak
3. Suggestions for additional content sections if thin

Current hero headline: {{ $json.currentContent.section?.[0]?.headline || 'none' }}

