const fix = $json.generatedContent;
const original = $('Detect SEO Issues').item.json;

// Build updated content with SEO fixes applied
const updatedContent = { ...original.currentContent };

// Update meta description
if (fix.metaDescription) {
  updatedContent.seo_description = fix.metaDescription;
}

// Update hero headline if present
if (fix.heroHeadline && Array.isArray(updatedContent.section)) {
  const hero = updatedContent.section.find(s => s.component === 'hero');
  if (hero) {
    hero.headline = fix.heroHeadline;
  }
}

return [{
  json: {
    storyId: original.storyId,
    slug: original.slug,
    updatedContent,
    fixes: fix,
    originalIssues: original.issues
  }
}];
